const message = $json.message || {};
const text = (message.text || '').trim();
const chatId = (message.chat?.id || '').toString();
const ownerId = ($env.TELEGRAM_OWNER_CHAT_ID || '').toString();

// Skip owner messages with PDFs (handled by indexer)
if (chatId === ownerId && message.document) return [];

// Skip empty messages
if (!text) return [];

const t = text.toLowerCase();
let intent = 'UNKNOWN';

if (/^(hola|hey|buenas|buenos|buen|saludos|hi|hello)/i.test(t)) {
  intent = 'GREETING';
} else if (/\b(pedir|pedido|quiero|domicilio|delivery|llevar|me trae|me da|me puede traer|encargar|para llevar)\b/i.test(t)) {
  intent = 'ORDER';
} else if (/\b(reserva|reservar|mesa|personas|fecha|aniversario|cumpleaños|celebración|evento|cena romántica)\b/i.test(t)) {
  intent = 'RESERVATION';
} else if (/\b(queja|problema|mal|frío|fría|tarde|insatisfecho|horrible|pésimo|nunca|decepcionante|reclamo|llegó mal|muy tarde|se demoró|cobr|equivoc)\b/i.test(t)) {
  intent = 'COMPLAINT';
} else if (/\b(gracias|excelente|delicioso|rico|buenísimo|genial|increíble|recomiendo|encantó|espectacular|el mejor|muy bueno|me gustó)\b/i.test(t)) {
  intent = 'FEEDBACK';
} else if (/\b(menú|menu|precio|vale|cuesta|tienes|tienen|hay|opciones|plato|comida|bebida|postre|entrada|vegano|vegetariano|sin gluten|especial|carta|especialidad|ajiaco|bandeja|caldo|sopa|ensalada|carne|pollo|pescado|pasta|pizza|postre|jugo|gaseosa|cerveza)\b/i.test(t)) {
  intent = 'MENU_QUERY';
} else if (/\b(hora|horario|abren|cierran|abierto|cerrado|cuando|dirección|dirección|ubicación|donde|cómo llegar|teléfono|contacto|parqueadero|parqueo|wifi|instagram|redes|pago|rappi|domicilios|aplicación|app)\b/i.test(t)) {
  intent = 'HOURS_INFO';
}

return [{ json: {
  chat_id: chatId,
  first_name: message.from?.first_name || 'Cliente',
  username: message.from?.username || '',
  text,
  message_id: message.message_id,
  intent,
  timestamp: new Date().toISOString()
} }];

const data = $input.item.json;
const orderId = 'PED-' + Date.now().toString().slice(-6);
return { json: {
  ...data,
  order_id: orderId,
  order_text: data.text,
  formatted_kitchen: `🍽️ *NUEVO PEDIDO ${orderId}*
⏰ ${new Date().toLocaleTimeString('es-CO')}
👤 ${data.first_name} (@${data.username || 'sin usuario'})
━━━━━━━━━━━━━━
${data.text}
━━━━━━━━━━━━━━
Chat ID: ${data.chat_id}`,
  formatted_client: `✅ ¡Pedido recibido, ${data.first_name}!

Tu pedido está en preparación.
Tiempo estimado: 30-45 min 🕐

Te notificamos cuando esté en camino.`
} };

const data = $input.item.json;
const resId = 'RES-' + Date.now().toString().slice(-6);
const peopleMatch = data.text.match(/(\d+)\s*(personas?|pax|person)/i);
const numPeople = peopleMatch ? peopleMatch[1] : 'por confirmar';
return { json: {
  ...data,
  res_id: resId,
  num_personas: numPeople,
  email_subject: `📅 Nueva reserva — La Fogata (${resId})`,
  email_body: `<h2>Nueva Reserva — La Fogata</h2><p><b>ID:</b> ${resId}</p><p><b>Cliente:</b> ${data.first_name} (@${data.username || 'sin usuario'})</p><p><b>Mensaje original:</b><br>${data.text}</p><p><b>Personas:</b> ${numPeople}</p><p><b>Chat ID para responder:</b> ${data.chat_id}</p><p><b>Timestamp:</b> ${data.timestamp}</p><hr><p>Responde al cliente directamente por Telegram con su Chat ID.</p>`,
  client_msg: `📅 ¡Reserva recibida, ${data.first_name}!\n\nNuestro equipo la revisará y te confirmará en menos de 2 horas ✅\n\n¿Dudas? Escríbenos aquí mismo.`
} };

const pineconeResult = $input.item.json;
const matches = pineconeResult.matches || [];

const bestScore = matches.length > 0 ? (matches[0].score || 0) : 0;
const lowConfidence = bestScore < 0.55;

const context = matches
  .map(m => m.metadata?.text || '')
  .filter(t => t.length > 0)
  .join('\n\n---\n\n');

const originalMessage = $('Detect Intent').item.json.text;
const firstName = $('Detect Intent').item.json.first_name;
const chatId = $('Detect Intent').item.json.chat_id;
const intent = $('Detect Intent').item.json.intent;
const timestamp = $('Detect Intent').item.json.timestamp;

return { json: {
  chat_id: chatId,
  first_name: firstName,
  text: originalMessage,
  intent,
  timestamp,
  bestScore,
  lowConfidence,
  context: context || 'No se encontró información relevante en el menú.',
  prompt: `Eres el asistente virtual de La Fogata, un restaurante colombiano.\n\nINFORMACIÓN DISPONIBLE:\n${context}\n\nPREGUNTA DEL CLIENTE (${firstName}):\n${originalMessage}\n\nINSTRUCCIONES:\n1. Responde SOLO con la información del contexto anterior.\n2. Si la información no está disponible responde exactamente: ESCALAR: [razón breve]\n3. Menciona precios en pesos colombianos (COP).\n4. Sé amigable, conciso y usa máximo 3 párrafos.\n5. Usa emojis de comida con moderación.\n6. Responde en español.`
} };

const input = $input.item.json;
const rawResponse = input.response || input.text || '';
const shouldEscalate = rawResponse.includes('ESCALAR:') || $('Build RAG Prompt').item.json.lowConfidence;
const escalateReason = shouldEscalate ? (rawResponse.match(/ESCALAR:\s*(.+)/)?.[1] || 'Pregunta fuera del alcance del bot') : '';
return { json: {
  chat_id: $('Detect Intent').item.json.chat_id,
  first_name: $('Detect Intent').item.json.first_name,
  text: $('Detect Intent').item.json.text,
  intent: $('Detect Intent').item.json.intent,
  timestamp: $('Detect Intent').item.json.timestamp,
  response: rawResponse,
  shouldEscalate,
  escalateReason,
  bestScore: $('Build RAG Prompt').item.json.bestScore
} };

const feedbackItems = $input.all().map(i => i.json);
const oneWeekAgo = new Date();
oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);

const weekFeedback = feedbackItems.filter(r => {
  try { return r.timestamp && new Date(r.timestamp) >= oneWeekAgo; } catch(e) { return false; }
});

const positivos = weekFeedback.filter(r => (r.sentimiento || '').toLowerCase() === 'positivo').length;
const negativos = weekFeedback.filter(r => (r.sentimiento || '').toLowerCase().includes('negat') || r.sentimiento === 'COMPLAINT').length;

const feedbackText = weekFeedback.length > 0
  ? weekFeedback.map(r => `[${r.sentimiento || 'N/A'}] ${r.cliente || 'N/A'}: "${r.mensaje || 'sin mensaje'}"`).join('\n')
  : 'Sin feedback esta semana.';

const weekStart = oneWeekAgo.toISOString().split('T')[0];
const weekEnd = new Date().toISOString().split('T')[0];

return [{ json: {
  totalFeedback: weekFeedback.length,
  positivos,
  negativos,
  feedbackText,
  weekStart,
  weekEnd
} }];

const ctx = $('Build Report Context').first().json;
const narrative = ($input.first().json.response || $input.first().json.text || 'Reporte no disponible')
  .replace(/</g,'&lt;').replace(/>/g,'&gt;')
  .replace(/\n/g,'<br>')
  .replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>');

const html = `<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f8f9fa;font-family:'Segoe UI',Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="padding:32px 16px;"><tr><td align="center"><table width="580" cellpadding="0" cellspacing="0"><tr><td style="background:linear-gradient(135deg,#b91c1c,#dc2626);border-radius:16px 16px 0 0;padding:28px 32px;"><p style="margin:0 0 4px;color:rgba(255,255,255,0.7);font-size:11px;text-transform:uppercase;letter-spacing:.1em;">Resumen Semanal Automatizado</p><h1 style="margin:0 0 6px;color:#fff;font-size:20px;">🍽️ La Fogata — Informe Semanal</h1><p style="margin:0;color:rgba(255,255,255,0.85);font-size:13px;">${ctx.weekStart} al ${ctx.weekEnd}</p></td></tr><tr><td style="background:#fff;padding:24px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td width="33%" style="padding:0 6px 0 0"><div style="background:#fef2f2;border-radius:10px;padding:14px;text-align:center"><div style="font-size:26px;font-weight:800;color:#b91c1c">${ctx.totalFeedback}</div><div style="font-size:10px;color:#6b7280;text-transform:uppercase;margin-top:3px">Total feedback</div></div></td><td width="33%" style="padding:0 3px"><div style="background:#f0fdf4;border-radius:10px;padding:14px;text-align:center"><div style="font-size:26px;font-weight:800;color:#16a34a">${ctx.positivos}</div><div style="font-size:10px;color:#6b7280;text-transform:uppercase;margin-top:3px">Positivos</div></div></td><td width="33%" style="padding:0 0 0 6px"><div style="background:#fef9c3;border-radius:10px;padding:14px;text-align:center"><div style="font-size:26px;font-weight:800;color:#ca8a04">${ctx.negativos}</div><div style="font-size:10px;color:#6b7280;text-transform:uppercase;margin-top:3px">A mejorar</div></div></td></tr></table></td></tr><tr><td style="background:#fff;padding:0 24px 24px"><div style="background:#f8f9fa;border-left:4px solid #b91c1c;border-radius:0 10px 10px 0;padding:18px"><p style="margin:0 0 10px;font-size:11px;font-weight:700;color:#b91c1c;text-transform:uppercase;letter-spacing:.08em">Análisis IA — Ollama llama3.2</p><div style="font-size:14px;line-height:1.7;color:#374151">${narrative}</div></div></td></tr><tr><td style="background:#1f2937;border-radius:0 0 16px 16px;padding:14px 24px;text-align:center"><p style="margin:0;color:#9ca3af;font-size:11px">La Fogata Bot · Flow 04 — Portfolio Cristian Silva</p></td></tr></table></td></tr></table></body></html>`;

return [{ json: {
  html,
  subject: `🌟 La Fogata — Resumen semanal ${ctx.weekStart} al ${ctx.weekEnd} · ${ctx.totalFeedback} feedbacks`
} }];
